import graph;

unitsize(2 cm);

pair O, A, B, C;

O = (0,0);
A = (-1,0);
B = (1,0);
C = dir(50);

draw(Circle(O,1));
draw(B--A--C--O);

label("$A$", A, W);
label("$B$", B, E);
label("$C$", C, NE);
label("$O$", O, S);
[/asy]

